179	export interface ThreeMmdLoaderOptions {
180	  /** Resolves MMD-relative texture paths when loading model materials. */
181	  readonly textureResolver?: TextureResolver;
182	  /** Maps MMD-relative texture paths to browser-loadable texture sources. */
183	  readonly textureMap?: TextureMap;
184	  /** Overrides the default Three.js texture loader for ordinary textures. */
185	  readonly textureLoader?: ThreeMmdTextureLoader;
186	  /** Overrides the texture loader used for DDS textures. */
187	  readonly ddsLoader?: ThreeMmdTextureLoader;
188	  /** Enables geometry-aware texture alpha checks. Defaults to off, except when outlines require it internally. */
189	  readonly geometryAwareAlpha?: boolean;
190	  /** Options forwarded to the per-model runtime. */
191	  readonly runtime?: DefaultMmdRuntimeOptions;
192	  /** Creates a per-model runtime. When omitted, the bundled mmd-anim runtime is used for PMX. */
193	  readonly runtimeFactory?: (context: ThreeMmdRuntimeFactoryContext) => MmdRuntime;
194	  /** Parser core override. When omitted, the loader uses the TypeScript parser core. */
195	  readonly core?: MmdCore | Promise<MmdCore>;
196	  /** Overrides fetch for string ModelSource values. */
197	  readonly fetch?: ModelSourceFetch;
198	  /** Enables load-time performance marks and diagnostics. */
199	  readonly performance?: boolean | LoaderPerformanceOptions;
200	  /** Receives recoverable parser-core failures before falling back to the TypeScript parser. */
