320	export class ThreeMmdLoader {
321	  private readonly textureCache = new Map<string, Promise<THREE.Texture | undefined>>();
322	  private corePromise: Promise<MmdCore> | undefined;
323	  private fallbackCore: FallbackCore | undefined;
324	  private readonly useExplicitCore: boolean;
325	  private coreDiagnostic: ThreeMmdCoreDiagnostic;
326	  private implicitMmdAnimWasmReady = false;
327	
328	  constructor(readonly options: ThreeMmdLoaderOptions = {}) {
329	    validateLoaderOptions(options);
330	    this.useExplicitCore = options.core !== undefined;
331	    this.coreDiagnostic = this.useExplicitCore ? { kind: "provided" } : { kind: "wasm" };
332	    if (options.core) {
333	      this.corePromise = Promise.resolve(options.core);
334	    }
335	  }
336	
337	  async loadModel(
338	    source: ModelSource,
339	    options: ThreeMmdLoadModelOptions = {}
340	  ): Promise<ThreeMmdModel> {
341	    validateModelSource(source, "loadModel");
342	    validateLoadModelOptions(options);
343	    const profile = createLoaderPerformanceProfile(
344	      describeModelSourceForPerformance(source),
345	      normalizeLoaderPerformanceOptions(this.options.performance)
346	    );
347	    profile?.mark("start");
348	    try {
349	      const { bytes, diagnostic: sourceDiagnostic } = await readModelSource(source, {
350	        fetch: options.fetch ?? this.options.fetch,
351	        signal: options.signal
352	      });
353	      profile?.mark("bytes");
354	      const core = await this.getCore();
355	      const { model: parsedModel, coreDiagnostic } = this.loadCoreModel(core, bytes);
356	      const modelData = createLoaderMmdModelDataFromModel(parsedModel);
357	      let parsedModelDisposed = false;
358	      try {
359	        profile?.mark("parsed");
360	        const mesh = createThreeMmdMesh(modelData);
361	        parsedModel.dispose?.();
362	        parsedModelDisposed = true;
363	        profile?.mark("mesh");
364	        const materials = normalizeMeshMaterials(mesh.material);
365	        warnDeprecatedLoadModelOptions(options);
366	        const effectiveOutlines = options.outline ?? options.outlines ?? true;
367	        const materialDiagnostics: MaterialTransparencyDiagnostic[] = [];
368	        const textureDiagnostics = await applyThreeMmdMaterialTextures(materials, modelData.materials, {
369	          textureResolver: this.options.textureResolver,
370	          textureMap: this.options.textureMap,
371	          textureLoader: this.options.textureLoader,
372	          ddsLoader: this.options.ddsLoader,
373	          modelUrl: typeof source === "string" ? source : undefined,
374	          geometry: mesh.geometry,
375	          morphs: modelData.morphs,
376	          geometryAwareAlpha: this.options.geometryAwareAlpha || effectiveOutlines,
377	          materialDiagnostics,
378	          textureCache: this.textureCache
379	        });
380	        profile?.mark("textures");
381	        const renderOrder = computeMmdMaterialRenderOrder(
382	          materials.map((material, materialIndex) => ({
383	            materialIndex,
384	            transparencyMode: material.userData.mmdMaterial?.transparencyMode ?? "opaque"
385	          }))
386	        );
387	        mesh.userData.mmdMaterialRenderOrder = renderOrder;
388	        syncMmdModelShadowFlags(mesh, modelData.materials);
389	        if (options.frustumCulled !== undefined) {
390	          mesh.frustumCulled = options.frustumCulled;
391	        }
392	        syncMorphSplitBodyMeshRenderState(mesh, modelData.materials);
393	        profile?.mark("materials");
394	        const sourceDescriptor = createModelSourceDescriptor(source, bytes.byteLength);
395	        const model = createThreeMmdModel({
396	          mesh,
397	          runtime: this.createRuntime({
398	            modelBytes: bytes,
399	            mesh,
400	            source: sourceDescriptor
401	          }),
402	          source: sourceDescriptor,
403	          sourceDiagnostic,
404	          coreDiagnostic,
405	          textureDiagnostics,
406	          materialDiagnostics,
407	          performanceDiagnostics: profile?.measures ?? [],
408	          materials: modelData.materials,
409	          outlines: effectiveOutlines,
410	          renderOrderProxies: options.materialRenderOrder ?? options.renderOrderProxies ?? true
411	        });
412	        profile?.mark("assembled");
413	        profile?.measure("read-bytes", "start", "bytes");
414	        profile?.measure("parse-model", "bytes", "parsed");
415	        profile?.measure("create-mesh", "parsed", "mesh");
416	        profile?.measure("load-textures", "mesh", "textures");
417	        profile?.measure("material-metadata", "textures", "materials");
418	        profile?.measure("assemble-model", "materials", "assembled");
419	        profile?.measure("total", "start", "assembled");
420	        return model;
421	      } finally {
422	        if (!parsedModelDisposed) {
423	          parsedModel.dispose?.();
424	        }
425	      }
426	    } finally {
427	      profile?.clear();
428	    }
429	  }
430	
431	  private createRuntime(context: ThreeMmdRuntimeFactoryContext): MmdRuntime {
432	    const explicitRuntime = this.options.runtimeFactory?.(context);
433	    if (explicitRuntime) {
434	      return explicitRuntime;
435	    }
436	    if (this.canCreateImplicitMmdAnimRuntime(context)) {
437	      try {
438	        return MmdAnimRuntime.fromPmxBytes(
439	          mmdAnimWasm as unknown as MmdAnimRuntimeWasmModule,
440	          context.modelBytes,
441	          normalizeMmdAnimRuntimeOptions(this.options.runtime)
442	        );
443	      } catch {
444	        return new DefaultMmdRuntime(this.options.runtime);
445	      }
446	    }
447	    return new DefaultMmdRuntime(this.options.runtime);
448	  }
449	
450	  private canCreateImplicitMmdAnimRuntime(context: ThreeMmdRuntimeFactoryContext): boolean {
451	    return (
452	      this.implicitMmdAnimWasmReady &&
453	      !this.useExplicitCore &&
454	      isPmxBytes(context.modelBytes) &&
455	      this.options.runtime?.physics !== "stateful-spring"
456	    );
457	  }
458	
459	  private getCore(): Promise<MmdCore> {
460	    this.corePromise ??= this.initCoreWithObservableFallback();
461	    return this.corePromise;
462	  }
463	
464	  private async initCoreWithObservableFallback(): Promise<MmdCore> {
465	    try {
466	      const core = await initCore();
467	      if (core instanceof FallbackCore) {
468	        this.fallbackCore = core;
469	        this.coreDiagnostic = {
470	          kind: "fallback",
471	          operation: "initCore",
472	          reason: "WASM core disabled; using TypeScript fallback parser."
473	        };
474	        this.implicitMmdAnimWasmReady = false;
475	      } else {
476	        this.coreDiagnostic = { kind: "wasm" };
477	        this.implicitMmdAnimWasmReady = true;
478	      }
479	      return core;
480	    } catch (error) {
481	      this.options.onCoreFallback?.({ operation: "initCore", error });
482	      this.coreDiagnostic = {
483	        kind: "fallback",
484	        operation: "initCore",
485	        reason: formatDiagnosticReason(error)
486	      };
487	      this.implicitMmdAnimWasmReady = false;
488	      this.fallbackCore ??= new FallbackCore();
489	      return this.fallbackCore;
490	    }
491	  }
492	
493	  private loadCoreModel(
494	    core: MmdCore,
495	    bytes: Uint8Array
496	  ): { readonly model: ReturnType<MmdCore["loadModel"]>; readonly coreDiagnostic: ThreeMmdCoreDiagnostic } {
497	    try {
498	      const model = core.loadModel(bytes);
499	      return {
500	        model,
501	        coreDiagnostic: this.createSuccessfulCoreDiagnostic(core)
502	      };
503	    } catch (error) {
504	      if (this.useExplicitCore) {
505	        throw error;
506	      }
507	      this.options.onCoreFallback?.({ operation: "loadModel", error });
508	      const coreDiagnostic: ThreeMmdCoreDiagnostic = {
509	        kind: "fallback",
510	        operation: "loadModel",
511	        reason: formatDiagnosticReason(error)
512	      };
513	      this.fallbackCore ??= new FallbackCore();
514	      return {
515	        model: this.fallbackCore.loadModel(bytes),
516	        coreDiagnostic
517	      };
518	    }
519	  }
520	
521	  private loadCoreVmd(core: MmdCore, bytes: Uint8Array): MmdAnimation {
522	    try {
523	      const animation = core.loadVmd(bytes);
524	      this.recordSuccessfulCoreUse(core);
525	      return animation;
526	    } catch (error) {
527	      if (this.useExplicitCore) {
528	        throw error;
529	      }
530	      this.options.onCoreFallback?.({ operation: "loadVmd", error });
531	      this.coreDiagnostic = {
532	        kind: "fallback",
533	        operation: "loadVmd",
534	        reason: formatDiagnosticReason(error)
535	      };
536	      this.fallbackCore ??= new FallbackCore();
537	      return this.fallbackCore.loadVmd(bytes);
538	    }
539	  }
540	
541	  private recordSuccessfulCoreUse(core: MmdCore): void {
542	    this.coreDiagnostic = this.createSuccessfulCoreDiagnostic(core);
543	  }
544	
545	  private createSuccessfulCoreDiagnostic(core: MmdCore): ThreeMmdCoreDiagnostic {
546	    if (this.useExplicitCore) {
547	      return { kind: "provided" };
548	    }
549	    if (core !== this.fallbackCore) {
550	      return { kind: "wasm" };
551	    }
552	    return this.coreDiagnostic;
553	  }
554	
555	  async loadAnimation(source: ModelSource): Promise<ThreeMmdAnimation> {
556	    validateModelSource(source, "loadAnimation");
557	    const bytes = await readModelSourceBytes(source, { fetch: this.options.fetch });
558	    if (bytes.byteLength === 0) {
559	      throw createEmptySourceError("loadAnimation");
560	    }
561	    const core = await this.getCore();
562	    const animation = this.loadCoreVmd(core, bytes);
563	    return {
564	      source,
565	      name: animation.metadata.modelName,
566	      animation
567	    };
568	  }
569	
570	  async loadPose(source: ModelSource): Promise<ThreeMmdPose> {
571	    validateModelSource(source, "loadPose");
572	    const bytes = await readModelSourceBytes(source, { fetch: this.options.fetch });
573	    if (bytes.byteLength === 0) {
574	      throw createEmptySourceError("loadPose");
575	    }
576	    return {
577	      source,
578	      pose: parseVpd(bytes)
579	    };
580	  }
581	
582	  async loadPoseAnimation(
583	    source: ModelSource,
584	    name = "pose"
585	  ): Promise<ThreeMmdAnimation> {
586	    validateModelSource(source, "loadPoseAnimation");
587	    const bytes = await readModelSourceBytes(source, { fetch: this.options.fetch });
588	    if (bytes.byteLength === 0) {
589	      throw createEmptySourceError("loadPoseAnimation");
590	    }
591	    const pose = parseVpd(bytes);
592	    const animation = createMmdAnimationFromPose(pose, name);
593	    return {
594	      source,
595	      name,
596	      animation
597	    };
598	  }
599	}
