601	function createThreeMmdModel(options: {
602	  readonly mesh: THREE.SkinnedMesh;
603	  readonly runtime: MmdRuntime;
604	  readonly source: ThreeMmdModelSourceDescriptor;
605	  readonly sourceDiagnostic: ModelSourceDiagnostic;
606	  readonly coreDiagnostic: ThreeMmdCoreDiagnostic;
607	  readonly textureDiagnostics: readonly TextureLoadDiagnostic[];
608	  readonly materialDiagnostics: readonly MaterialTransparencyDiagnostic[];
609	  readonly performanceDiagnostics: readonly LoaderPerformanceMeasure[];
610	  readonly materials: readonly LoaderMmdModelData["materials"][number][];
611	  readonly outlines: boolean;
612	  readonly renderOrderProxies: boolean;
613	}): ThreeMmdModel {
614	  const bodyMeshes = readMorphSplitBodyMeshes(options.mesh);
615	  const outlineSources = bodyMeshes.length > 0 ? bodyMeshes : [options.mesh];
616	  const outlineMeshes = options.outlines
617	    ? outlineSources.flatMap((mesh) =>
618	        createMmdOutlineMeshes({
619	          mesh,
620	          materials: options.materials
621	        })
622	      )
623	    : [];
624	  if (options.materials.some((material) => mmdMaterialCastsSelfShadow(material.flags))) {
625	    options.mesh.layers.enable(MMD_SELF_SHADOW_LAYER);
626	  }
627	  outlineMeshes.forEach((outline) => {
