1	/**
2	 * Generates minimal VMD animation files for skinning visual regression.
3	 *
4	 * VMD binary layout:
5	 *   30 bytes  signature ("Vocaloid Motion Data 0002", null-padded)
6	 *   20 bytes  model name (Shift-JIS, null-padded; any value — not matched to PMX)
7	 *   4 bytes   bone frame count (i32 LE)
8	 *   per bone frame:
9	 *     15 bytes  bone name (Shift-JIS, null-padded)
10	 *      4 bytes  frame number (u32 LE)
11	 *     12 bytes  translation xyz (f32 × 3)
12	 *     16 bytes  rotation quaternion xyzw (f32 × 4)
13	 *     64 bytes  bezier interpolation (linear defaults: 20 20 107 107 pattern)
14	 *   4 bytes   morph frame count (i32 LE) = 0
15	 *   4 bytes   camera frame count (i32 LE) = 0
16	 *   4 bytes   light frame count (i32 LE) = 0
17	 *   4 bytes   self-shadow frame count (i32 LE) = 0
18	 *   4 bytes   property frame count (i32 LE) = 0
19	 */
20	
21	import { mkdir, writeFile } from "node:fs/promises";
22	import { dirname, resolve } from "node:path";
23	import { fileURLToPath } from "node:url";
24	
25	const SKINNING_VMD_OUTPUT_DIR = "test/fixtures/generated/skinning";
26	const CAMERA_LIGHT_VMD_OUTPUT_DIR = "test/fixtures/generated/camera-light-vmd";
27	
28	// Linear bezier interpolation control points (standard MMD defaults).
29	// Layout: 4 axes (X,Y,Z,R) × 16 bytes each, interleaved in a specific pattern.
30	// Using the common linear values: x1=x2=20, y1=y2=107 for each axis.
31	const LINEAR_INTERPOLATION = new Uint8Array([
32	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
33	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
34	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
35	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
36	]);
37	const LINEAR_CAMERA_INTERPOLATION = new Uint8Array([
38	  20, 20, 20, 20, 20, 20,
39	  20, 20, 20, 20, 20, 20,
40	  107, 107, 107, 107, 107, 107,
41	  107, 107, 107, 107, 107, 107
42	]);
43	
44	/**
45	 * Generates a VMD with one keyframe per entry in `boneFrames`.
46	 *
47	 * @param {object} options
48	 * @param {string} [options.modelName]  Model name written into VMD header (cosmetic).
49	 * @param {Array<{boneName: string, frame?: number, quaternion: [number,number,number,number]}>} options.boneFrames
50	 *   Each entry sets one bone keyframe. quaternion = [x, y, z, w].
51	 * @param {Array<{frame?: number, distance: number, position: [number,number,number], rotation: [number,number,number], fov: number, perspective?: boolean}>} [options.cameraFrames]
52	 * @param {Array<{frame?: number, color: [number,number,number], direction: [number,number,number]}>} [options.lightFrames]
53	 * @param {Array<{frame?: number, mode: number, distance: number}>} [options.selfShadowFrames]
54	 * @returns {Uint8Array}
55	 */
56	export function generateMinimalVmd({
57	  modelName = "",
58	  boneFrames = [],
59	  cameraFrames = [],
60	  lightFrames = [],
61	  selfShadowFrames = []
62	}) {
63	  const out = [];
64	
65	  const u32 = (v) => {
66	    const b = new ArrayBuffer(4);
67	    new DataView(b).setUint32(0, v, true);
68	    out.push(...new Uint8Array(b));
69	  };
70	  const i32 = (v) => {
71	    const b = new ArrayBuffer(4);
72	    new DataView(b).setInt32(0, v, true);
73	    out.push(...new Uint8Array(b));
74	  };
75	  const f32 = (v) => {
76	    const b = new ArrayBuffer(4);
77	    new DataView(b).setFloat32(0, v, true);
78	    out.push(...new Uint8Array(b));
79	  };
80	  const fixedText = (s, length) => {
81	    // ASCII/Shift-JIS: ASCII subset works directly as byte values
82	    for (let i = 0; i < length; i++) {
83	      out.push(i < s.length ? s.charCodeAt(i) : 0);
84	    }
85	  };
86	
87	  // Signature (30 bytes)
88	  fixedText("Vocaloid Motion Data 0002", 30);
89	  // Model name (20 bytes)
90	  fixedText(modelName.substring(0, 20), 20);
91	
92	  // Bone frame count
93	  i32(boneFrames.length);
94	
95	  for (const bf of boneFrames) {
96	    fixedText(bf.boneName, 15);                    // bone name (15 bytes)
97	    u32(bf.frame ?? 0);                            // frame number
98	    f32(0); f32(0); f32(0);                        // translation (zero)
99	    const [qx, qy, qz, qw] = bf.quaternion;
100	    f32(qx); f32(qy); f32(qz); f32(qw);           // rotation quaternion
101	    out.push(...LINEAR_INTERPOLATION);             // interpolation (64 bytes)
102	  }
103	
104	  // Morph frames
105	  i32(0);
106	  // Camera frames
107	  i32(cameraFrames.length);
108	  for (const frame of cameraFrames) {
109	    u32(frame.frame ?? 0);
110	    f32(frame.distance);
111	    f32(frame.position[0]); f32(frame.position[1]); f32(frame.position[2]);
112	    f32(frame.rotation[0]); f32(frame.rotation[1]); f32(frame.rotation[2]);
113	    out.push(...LINEAR_CAMERA_INTERPOLATION);
114	    u32(frame.fov);
115	    out.push(frame.perspective === false ? 1 : 0);
116	  }
117	  // Light frames
118	  i32(lightFrames.length);
119	  for (const frame of lightFrames) {
120	    u32(frame.frame ?? 0);
121	    f32(frame.color[0]); f32(frame.color[1]); f32(frame.color[2]);
122	    f32(frame.direction[0]); f32(frame.direction[1]); f32(frame.direction[2]);
123	  }
124	  i32(selfShadowFrames.length);
125	  for (const frame of selfShadowFrames) {
126	    u32(frame.frame ?? 0);
127	    out.push(frame.mode & 0xff);
128	    f32(frame.distance);
129	  }
130	  // property
131	  i32(0);
132	
133	  return new Uint8Array(out);
134	}
135	
136	// ──────────────────────────────────────────────────────────────────────────────
137	// Named VMD fixtures for skinning visual tests
138	// ──────────────────────────────────────────────────────────────────────────────
139	
140	// Rotate around the Z axis by `deg` degrees — elbow-like sideways bend for a Y-axis limb.
141	// Quaternion for Z rotation: [0, 0, sin(θ/2), cos(θ/2)]
142	function rotZ(deg) {
143	  const r = (deg * Math.PI) / 180;
144	  return [0, 0, Math.sin(r / 2), Math.cos(r / 2)];
145	}
146	
147	// Rotate around the Y axis by `deg` degrees — axial twist.
148	function rotY(deg) {
149	  const r = (deg * Math.PI) / 180;
150	  return [0, Math.sin(r / 2), 0, Math.cos(r / 2)];
151	}
152	
153	export const SKINNING_VMOD_CASES = {
154	  // 2-bone elbow bend: rotate upper bone 90° sideways (Z axis).
155	  // Upper half goes in +X direction, forming an L-shape visible from the front.
156	  "bend-two-bone-90": {
157	    modelName: "bend90",
158	    boneFrames: [
159	      { boneName: "upper",    frame: 0, quaternion: rotZ(90) },
160	      { boneName: "upperArm", frame: 0, quaternion: rotZ(90) }
161	    ]
162	  },
163	  // 4-bone twist: rotate top bone 120° around Y — shows candy-wrapper on BDEF4
164	  "twist-four-bone-120": {
165	    modelName: "twist120",
166	    boneFrames: [
167	      { boneName: "bone3", frame: 0, quaternion: rotY(120) }
168	    ]
169	  }
