281	if (process.argv[1] === fileURLToPath(import.meta.url)) {
282	  const outputArgIndex = process.argv.indexOf("--output-dir");
283	  const writeSelfShadow = process.argv.includes("--all-self-shadow");
284	  const writeCameraLight = process.argv.includes("--camera-light");
285	  const outputDir =
286	    outputArgIndex >= 0 && process.argv[outputArgIndex + 1] !== undefined
287	      ? process.argv[outputArgIndex + 1]
288	      : writeCameraLight
289	        ? CAMERA_LIGHT_VMD_OUTPUT_DIR
290	        : SKINNING_VMD_OUTPUT_DIR;
291	  const caseIds = writeCameraLight
292	    ? cameraLightVmdCaseIds()
293	    : writeSelfShadow
294	      ? selfShadowVmdCaseIds()
295	      : skinningVmdCaseIds();
296	  for (const caseId of caseIds) {
