300	      : writeSelfShadow
301	        ? generateSelfShadowVmd(caseId)
302	        : generateSkinningVmd(caseId);
303	    await mkdir(dirname(outputPath), { recursive: true });
304	    await writeFile(outputPath, bytes);
305	    console.log(`wrote ${bytes.byteLength} bytes to ${outputPath}`);
306	  }
