4	import { clampColor } from "../utils.js";
5	import { mmdMaterialDepthWrite, mmdMaterialSuppressesColorAtAlpha } from "./material-metadata.js";
6	
7	type ShaderUniformMap = Record<string, { value: unknown }>;
8	const mmdDirectionalLightPositionScratch = new THREE.Vector3();
9	const mmdDirectionalLightTargetScratch = new THREE.Vector3();
10	const mmdDirectionalLightNormalizedScratch = new THREE.Vector3();
