130	export function syncMmdSpecularDirection(
131	  material: THREE.Material | THREE.Material[],
132	  lightDirection: THREE.Vector3 | THREE.DirectionalLight
133	): void {
134	  const materialList = Array.isArray(material) ? material : [material];
135	  const directionSource = mmdLightDirectionSource(lightDirection);
136	  const directColor =
137	    lightDirection instanceof THREE.Light
138	      ? [
139	          lightDirection.visible ? lightDirection.color.r * lightDirection.intensity : 0,
140	          lightDirection.visible ? lightDirection.color.g * lightDirection.intensity : 0,
141	          lightDirection.visible ? lightDirection.color.b * lightDirection.intensity : 0
142	        ]
143	      : [1, 1, 1];
144	  materialList.forEach((mat) => {
145	    const normalizedDirection = mmdDirectionalLightNormalizedScratch.copy(directionSource).normalize();
146	    const lightUniformState = getMmdLightUniformState(mat);
147	    lightUniformState.direction[0] = normalizedDirection.x;
148	    lightUniformState.direction[1] = normalizedDirection.y;
149	    lightUniformState.direction[2] = normalizedDirection.z;
150	    lightUniformState.directColor[0] = directColor[0];
151	    lightUniformState.directColor[1] = directColor[1];
152	    lightUniformState.directColor[2] = directColor[2];
153	    const shader = mat.userData.mmdMaterialFactorShader as
154	      | { uniforms?: ShaderUniformMap }
155	      | undefined;
156	    const dir = shader?.uniforms?.mmdLightDirection?.value;
157	    if (dir instanceof THREE.Vector3) {
158	      dir.copy(normalizedDirection);
159	    }
160	    const color = shader?.uniforms?.mmdDirectLightColor?.value;
161	    if (color instanceof THREE.Color) {
162	      color.setRGB(directColor[0], directColor[1], directColor[2]);
163	    }
164	    const mmdLightColor = shader?.uniforms?.mmdLightColor?.value;
165	    if (mmdLightColor instanceof THREE.Color) {
166	      mmdLightColor.setRGB(directColor[0], directColor[1], directColor[2]);
167	    }
168	  });
169	}
