171	function getMmdLightUniformState(material: THREE.Material): {
172	  direction: [number, number, number];
173	  directColor: [number, number, number];
174	} {
175	  const existing = material.userData.mmdLightUniformState as
176	    | { direction?: unknown; directColor?: unknown }
177	    | undefined;
178	  if (
179	    existing &&
180	    Array.isArray(existing.direction) &&
181	    existing.direction.length >= 3 &&
182	    Array.isArray(existing.directColor) &&
183	    existing.directColor.length >= 3
184	  ) {
185	    return existing as {
186	      direction: [number, number, number];
187	      directColor: [number, number, number];
188	    };
189	  }
190	  const created = {
191	    direction: [0, 0, 1] as [number, number, number],
192	    directColor: [1, 1, 1] as [number, number, number]
193	  };
194	  material.userData.mmdLightUniformState = created;
195	  return created;
196	}
197	
198	function mmdLightDirectionSource(lightDirection: THREE.Vector3 | THREE.DirectionalLight): THREE.Vector3 {
199	  if (!(lightDirection instanceof THREE.DirectionalLight)) {
200	    return lightDirection;
201	  }
202	  lightDirection.updateMatrixWorld();
203	  lightDirection.target.updateMatrixWorld();
204	  mmdDirectionalLightPositionScratch.setFromMatrixPosition(lightDirection.matrixWorld);
205	  mmdDirectionalLightTargetScratch.setFromMatrixPosition(lightDirection.target.matrixWorld);
206	  return mmdDirectionalLightPositionScratch.sub(mmdDirectionalLightTargetScratch);
207	}
