29	const MMD_TEXTURE_FACTOR_HELPERS = [
30	  "vec3 ywMmdApplyMul( vec3 c, vec4 f ) {",
31	  "  return mix( vec3( 1.0 ), c * f.rgb, f.a );",
32	  "}",
33	  // sRGB <-> linear helpers so the MMD formula runs in gamma (sRGB) space (§1)
34	  // while still feeding Three's linear -> sRGB output encode correctly.
35	  "vec3 ywMmdLinearToGamma( vec3 c ) {",
36	  "  c = clamp( c, 0.0, 1.0 );",
37	  "  bvec3 cutoff = lessThanEqual( c, vec3( 0.0031308 ) );",
38	  "  vec3 lower = c * 12.92;",
39	  "  vec3 higher = pow( c, vec3( 1.0 / 2.4 ) ) * 1.055 - 0.055;",
40	  "  return mix( higher, lower, vec3( cutoff ) );",
41	  "}",
42	  "vec3 ywMmdGammaToLinear( vec3 c ) {",
43	  "  c = clamp( c, 0.0, 1.0 );",
44	  "  bvec3 cutoff = lessThanEqual( c, vec3( 0.04045 ) );",
45	  "  vec3 lower = c / 12.92;",
46	  "  vec3 higher = pow( ( c + 0.055 ) / 1.055, vec3( 2.4 ) );",
47	  "  return mix( higher, lower, vec3( cutoff ) );",
48	  "}"
49	].join("\n");
