56	  "uniform vec4 mmdTextureFactor;",
57	  "uniform vec4 mmdToonTextureFactor;",
58	  "uniform vec3 mmdDiffuseColor;",
59	  "uniform vec3 mmdMaterialAmbient;",
60	  "uniform vec3 mmdSpecularColor;",
61	  "uniform float mmdSpecularPower;",
62	  "uniform vec3 mmdLightDirection;",
63	  "uniform vec3 mmdLightColor;",
64	  "uniform float mmdSelfShadowReceive;",
65	  MMD_TOON_SHADOW_FACTOR_DECLARATION,
