69	/**
70	 * The complete MMD fragment composite (§2), evaluated in gamma (sRGB) space and then
71	 * converted back to linear so Three's sRGB output encode reproduces it.
72	 *
73	 * Inputs that come from the standard pipeline before <opaque_fragment>:
74	 *   - normal           : view-space normal (normal_fragment_begin)
75	 *   - vViewPosition    : view-space vertex position
76	 *   - diffuseColor.a   : material alpha * texture alpha (map_fragment / morph)
77	 *   - sampledMmdDiffuse: the diffuse texel in gamma space (or vec4(1) when no map)
78	 */
79	const MMD_OPAQUE_FRAGMENT = [
80	  "{",
81	  "  vec3 ywMmdNormal = normalize( vNormal );",
82	  // vViewPosition points from the fragment toward the camera; eyeDir in MMD/saba points
83	  // from the camera toward the fragment, hence the negation.
84	  "  vec3 ywMmdEyeDir = normalize( -vViewPosition );",
85	  // mmdLightDirection is the world-space direction toward the light. The normal is in
86	  // view space, so transform the light direction into view space before dotting.
87	  "  vec3 ywMmdLightDir = normalize( ( viewMatrix * vec4( mmdLightDirection, 0.0 ) ).xyz );",
88	  "  float ywMmdLn = dot( ywMmdNormal, ywMmdLightDir );",
89	  "  ywMmdLn = clamp( ywMmdLn * 0.5 + 0.5, 0.0, 1.0 );",
90	  `  ywMmdLn = mix( ${MMD_SELF_SHADOW_TOON_COORD_FLOOR.toFixed(2)}, ywMmdLn, ywMmdToonShadowFactor );`,
91	  "  vec3 ywMmdColor = mmdDiffuseColor * mmdLightColor;",
92	  "  ywMmdColor = clamp( ywMmdColor + mmdMaterialAmbient, 0.0, 1.0 );",
93	  "  #ifdef USE_MAP",
94	  // mmdTextureFactor is the morph-aggregated multiply tint (identity = (1,1,1,1)).
95	  "    vec3 ywMmdTex = ywMmdApplyMul( sampledMmdDiffuse.rgb, mmdTextureFactor );",
96	  "    ywMmdColor *= ywMmdTex;",
97	  "  #endif",
98	  "  #ifdef USE_MMD_SPHERE",
99	  // MMD matcap UV: project the view-space normal to [0,1] (§7 / saba mmd.frag).
100	  "    vec2 ywMmdSphereUv = vec2( ywMmdNormal.x * 0.5 + 0.5, 1.0 - ( ywMmdNormal.y * 0.5 + 0.5 ) );",
101	  // Sphere texture is configured SRGBColorSpace, so texture2D returns linear; re-encode
102	  // to gamma for the MMD (gamma-space) composite.
103	  "    vec3 ywMmdSphere = ywMmdLinearToGamma( texture2D( mmdSphereMap, ywMmdSphereUv ).rgb );",
104	  "    ywMmdSphere = ywMmdApplyMul( ywMmdSphere, mmdSphereFactor );",
105	  "    if ( mmdSphereMode == 1 ) { ywMmdColor *= ywMmdSphere; }",
106	  "    else if ( mmdSphereMode == 2 ) { ywMmdColor += ywMmdSphere; }",
107	  "    else if ( mmdSphereMode == 3 ) { ywMmdColor = mix( ywMmdColor, ywMmdSphere, mmdSphereFactor.a ); }",
108	  "  #endif",
109	  "  #ifdef USE_GRADIENTMAP",
110	  // Toon ramp (gradientMap) is configured NoColorSpace, so texture2D returns the stored
111	  // (gamma) ramp value directly.
112	  "    vec3 ywMmdToon = texture2D( gradientMap, vec2( 0.0, ywMmdLn ) ).rgb;",
113	  "    ywMmdToon = ywMmdApplyMul( ywMmdToon, mmdToonTextureFactor );",
114	  "    ywMmdColor *= ywMmdToon;",
115	  "  #endif",
116	  "  if ( mmdSpecularPower > 0.0 ) {",
117	  "    vec3 ywMmdHalf = normalize( ywMmdEyeDir + ywMmdLightDir );",
118	  "    ywMmdColor += pow( max( 0.0, dot( ywMmdHalf, ywMmdNormal ) ), mmdSpecularPower ) * mmdSpecularColor * mmdLightColor;",
119	  "  }",
120	  "  outgoingLight = ywMmdGammaToLinear( clamp( ywMmdColor, 0.0, 1.0 ) );",
121	  "}",
122	  "#include <opaque_fragment>"
123	].join("\n");
