130	  const previousProgramCacheKey = material.customProgramCacheKey.bind(material);
131	  const rawDiffuse = readMaterialRawDiffuse(material);
132	  const rawAmbient = readMaterialRawVec3(material, "ambient", [0, 0, 0]);
133	  const rawSpecular = readMaterialRawVec3(material, "specular", [0, 0, 0]);
134	  const rawSpecularPower = readMaterialRawSpecularPower(material);
135	  material.userData.mmdMaterialFactors = {
136	    shaderApplied: true,
137	    toonTextureFactorUniform: true,
138	    rawDiffuse
139	  };
