141	  // color from scratch. Keeping emissive at 0 also prevents material-sync from writing
142	  // ambient into it on the legacy path.
143	  if ("emissive" in material && (material as { emissive?: unknown }).emissive instanceof THREE.Color) {
144	    (material as { emissive: THREE.Color }).emissive.setRGB(0, 0, 0);
145	  }
146	  material.onBeforeCompile = (shader, renderer) => {
147	    previousOnBeforeCompile(shader, renderer);
