149	    shader.uniforms.mmdToonTextureFactor = { value: new THREE.Vector4(1, 1, 1, 1) };
150	    shader.uniforms.mmdDiffuseColor = {
151	      value: new THREE.Color(rawDiffuse[0], rawDiffuse[1], rawDiffuse[2])
152	    };
153	    shader.uniforms.mmdMaterialAmbient = {
154	      value: new THREE.Color(rawAmbient[0], rawAmbient[1], rawAmbient[2])
155	    };
156	    shader.uniforms.mmdSpecularColor = {
157	      value: new THREE.Color(rawSpecular[0], rawSpecular[1], rawSpecular[2])
158	    };
159	    shader.uniforms.mmdSpecularPower = { value: rawSpecularPower };
