241	function injectMmdShading(fragmentShader: string): string {
242	  let shader = fragmentShader;
243	  // Declare uniforms + helpers.
244	  shader = shader.replace(
245	    "#include <map_pars_fragment>",
246	    ["#include <map_pars_fragment>", MMD_FRAGMENT_PARS].join("\n")
247	  );
248	  // Capture the diffuse texel in gamma space (Three samples it as linear), and stop the
249	  // standard map_fragment from baking texture color into diffuseColor (we recompute it).
250	  shader = shader.replace(
251	    "#include <map_fragment>",
252	    [
253	      "#ifdef USE_MAP",
254	      "  vec4 ywMmdSampledDiffuse = texture2D( map, vMapUv );",
255	      "  vec4 sampledMmdDiffuse = vec4( ywMmdLinearToGamma( ywMmdSampledDiffuse.rgb ), ywMmdSampledDiffuse.a );",
256	      "  diffuseColor.a *= ywMmdSampledDiffuse.a;",
257	      "#else",
258	      "  vec4 sampledMmdDiffuse = vec4( 1.0 );",
259	      "#endif"
260	    ].join("\n")
261	  );
262	  // Replace the final composite with the MMD formula. We overwrite outgoingLight just
263	  // before <opaque_fragment> so alpha/discard/blend handling stays standard.
264	  shader = shader.replace("#include <opaque_fragment>", MMD_OPAQUE_FRAGMENT);
265	  // Drive the self-shadow factor from the directional shadow map (when present), so the
266	  // toon coordinate is attenuated for shadowed fragments (§10). On scenes without a
267	  // shadow map this leaves ywMmdToonShadowFactor at 1.0.
268	  shader = shader.replace(
269	    "#include <lights_fragment_begin>",
270	    mmdLightsFragmentBegin(MMD_DIRECTIONAL_SELF_SHADOW_FACTOR)
271	  );
272	  return shader;
273	}
