275	function mmdLightsFragmentBegin(shadowReplacement: string): string {
276	  return THREE.ShaderChunk.lights_fragment_begin
277	    .replace(
278	      DIRECTIONAL_LIGHT_INFO_CALL,
279	      [DIRECTIONAL_LIGHT_INFO_CALL].join("\n")
280	    )
281	    .replace(DIRECTIONAL_SHADOW_COLOR_MULTIPLY, shadowReplacement);
282	}
