284	function readMaterialRawDiffuse(material: THREE.Material): [number, number, number] {
285	  const diffuse = material.userData.mmdMaterial?.diffuse as
286	    | [number, number, number, number]
287	    | undefined;
288	  if (diffuse) {
289	    return [clampColor(diffuse[0]), clampColor(diffuse[1]), clampColor(diffuse[2])];
290	  }
291	  const color = (material as { color?: unknown }).color;
292	  if (color instanceof THREE.Color) {
293	    // Fallback: Three stores material.color in linear working space; convert to gamma.
294	    const gamma = color.clone().convertLinearToSRGB();
295	    return [gamma.r, gamma.g, gamma.b];
296	  }
297	  return [1, 1, 1];
298	}
