300	function readMaterialRawVec3(
301	  material: THREE.Material,
302	  key: "ambient" | "specular",
303	  fallback: [number, number, number]
304	): [number, number, number] {
305	  const value = material.userData.mmdMaterial?.[key] as
306	    | [number, number, number]
307	    | undefined;
308	  if (value) {
309	    return [clampColor(value[0]), clampColor(value[1]), clampColor(value[2])];
310	  }
311	  return fallback;
