330	export function attachMmdSphereTexture(
331	  material: THREE.Material,
332	  sphereMode: MaterialInfo["sphereMode"],
333	  texture: THREE.Texture | undefined
334	): void {
335	  if (!texture || sphereMode === "none") {
336	    return;
337	  }
338	  if (!texture.userData.mmdTextureInfo) {
339	    configureMmdTexture(texture);
340	  }
341	  const previousOnBeforeCompile = material.onBeforeCompile.bind(material);
342	  const previousProgramCacheKey = material.customProgramCacheKey.bind(material);
343	  material.userData.mmdSphereMap = {
344	    mode: sphereMode,
345	    texture,
346	    shaderApplied: true
347	  };
348	  material.onBeforeCompile = (shader, renderer) => {
349	    previousOnBeforeCompile(shader, renderer);
350	    shader.uniforms.mmdSphereMap = { value: texture };
351	    shader.uniforms.mmdSphereMode = { value: mmdSphereModeToUniform(sphereMode) };
352	    shader.uniforms.mmdSphereFactor = { value: new THREE.Vector4(1, 1, 1, 1) };
353	    material.userData.mmdSphereShader = shader;
354	    // Declare sphere uniforms and enable the USE_MMD_SPHERE branch in the main MMD
355	    // shading block (material-shader-hooks injected before this hook runs).
356	    shader.fragmentShader = shader.fragmentShader.replace(
357	      "#include <map_pars_fragment>",
358	      [
359	        "#include <map_pars_fragment>",
360	        "#define USE_MMD_SPHERE",
361	        "uniform sampler2D mmdSphereMap;",
362	        "uniform int mmdSphereMode;",
363	        "uniform vec4 mmdSphereFactor;"
364	      ].join("\n")
365	    );
366	  };
367	  material.customProgramCacheKey = () =>
368	    `${previousProgramCacheKey()}-yw-mmd-sphere-${sphereMode}`;
369	  material.needsUpdate = true;
370	}
371	
372	export function mmdSphereModeToUniform(sphereMode: MaterialInfo["sphereMode"]): number {
373	  switch (sphereMode) {
374	    case "multiply":
375	      return 1;
376	    case "add":
377	      return 2;
378	    case "subTexture":
379	      return 3;
380	    default:
381	      return 0;
382	  }
383	}
