300	async function startStaticServer(dataRoot) {
301	  const server = createServer(async (request, response) => {
302	    const requestUrl = new URL(request.url ?? "/", "http://127.0.0.1");
303	
304	    if (requestUrl.pathname === "/__real_model_visual_renderer__") {
305	      response.writeHead(200, { "content-type": "text/html; charset=utf-8" });
306	      response.end(rendererHtml());
307	      return;
308	    }
309	
310	    const filePath = resolveRequestPath(requestUrl.pathname, dataRoot);
311	    if (filePath === undefined) {
312	      response.writeHead(403);
313	      response.end("Forbidden");
314	      return;
315	    }
316	
317	    try {
318	      const body = await readFile(filePath);
319	      response.writeHead(200, {
320	        "content-type": mimeTypes.get(path.extname(filePath).toLowerCase()) ?? "application/octet-stream"
321	      });
322	      response.end(body);
323	    } catch {
324	      response.writeHead(404);
325	      response.end("Not found");
326	    }
327	  });
328	
329	  await new Promise((resolve, reject) => {
330	    server.once("error", reject);
331	    server.listen(0, "127.0.0.1", () => {
332	      server.off("error", reject);
333	      resolve();
334	    });
335	  });
336	
337	  const address = server.address();
338	  return {
339	    origin: `http://127.0.0.1:${address.port}`,
340	    close: () => new Promise(resolve => server.close(resolve))
341	  };
342	}
