348	    const filePath = path.resolve(dataRoot, relativePath);
349	    return isInsideRoot(filePath, dataRoot) ? filePath : undefined;
350	  }
351	
352	  const normalizedPath = decodePath(requestPath).replace(/^[/\\]+/, "");
