163	export function syncAudioToMotionTime(options) {
164	  const active = hasActiveAudioSource();
165	  if (!isAudioElement(dom.bgmAudio) || !active) {
166	    return;
167	  }
168	  const duration = Number.isFinite(dom.bgmAudio.duration) ? dom.bgmAudio.duration : undefined;
169	  const offsetTargetTime = state.elapsedSeconds - state.audioOffsetSeconds;
170	  const targetTime = duration ? Math.min(Math.max(offsetTargetTime, 0), Math.max(duration - 0.001, 0)) : Math.max(offsetTargetTime, 0);
171	  if (options?.onlyIfDrifted && Math.abs(dom.bgmAudio.currentTime - targetTime) < 0.05) {
172	    return;
173	  }
174	  try {
175	    state.isSyncingAudioTime = true;
176	    if (state.audioSeekSyncTimer !== undefined) {
177	      window.clearTimeout(state.audioSeekSyncTimer);
178	    }
179	    dom.bgmAudio.currentTime = Math.max(targetTime, 0);
180	    state.audioSeekSyncTimer = window.setTimeout(() => {
181	      state.isSyncingAudioTime = false;
182	      state.audioSeekSyncTimer = undefined;
183	    }, 250);
184	  } catch (error) {
185	    state.isSyncingAudioTime = false;
186	    window.console?.warn("[viewer] Failed to seek audio:", error);
187	  }
188	}
