190	export function finishAudioTimeSync() {
191	  if (!state.isSyncingAudioTime) {
192	    return false;
193	  }
194	  state.isSyncingAudioTime = false;
195	  if (state.audioSeekSyncTimer !== undefined) {
196	    window.clearTimeout(state.audioSeekSyncTimer);
197	    state.audioSeekSyncTimer = undefined;
198	  }
199	  return true;
200	}
