102	export async function compareCase({ id, baselinePath, currentPath, diffPath, thresholds, metric = "js", flipPath }) {
103	  if (!existsSync(baselinePath)) {
104	    throw new Error(`Missing baseline PNG for ${id}: ${path.relative(repoRoot, baselinePath)}`);
105	  }
106	  if (!existsSync(currentPath)) {
107	    throw new Error(`Missing current PNG for ${id}: ${path.relative(repoRoot, currentPath)}`);
108	  }
109	
110	  const [baseline, current] = await Promise.all([readPng(baselinePath), readPng(currentPath)]);
111	  if (baseline.width !== current.width || baseline.height !== current.height) {
112	    throw new Error(
113	      `Image size mismatch for ${id}: baseline=${baseline.width}x${baseline.height}, current=${current.width}x${current.height}`
114	    );
115	  }
116	
117	  if (metric === "flip") {
118	    return await compareCaseWithFlip({
119	      id,
120	      baselinePath,
121	      currentPath,
122	      diffPath,
123	      thresholds,
124	      flipPath
125	    });
126	  }
127	
128	  const pixelCount = baseline.width * baseline.height;
129	  const distances = new Float64Array(pixelCount);
130	  const diff = new PNG({ width: baseline.width, height: baseline.height });
131	  let sum = 0;
132	  let max = 0;
133	
134	  for (let pixel = 0; pixel < pixelCount; pixel += 1) {
135	    const offset = pixel * 4;
136	    const distance = perceptualDistance(baseline.data, current.data, offset);
137	    distances[pixel] = distance;
138	    sum += distance;
139	    max = Math.max(max, distance);
140	    writeHeatmapPixel(diff.data, offset, distance);
141	  }
142	
143	  distances.sort();
144	  const mean = sum / pixelCount;
145	  const p95 = distances[Math.min(distances.length - 1, Math.ceil(distances.length * 0.95) - 1)];
146	  const pass = mean <= thresholds.mean && p95 <= thresholds.p95;
147	
148	  await writePng(diff, diffPath);
149	
150	  return {
151	    case: id,
152	    metric,
153	    mean: roundMetric(mean),
154	    p95: roundMetric(p95),
155	    max: roundMetric(max),
156	    thresholds,
157	    pass
158	  };
159	}
