165	    "--reference",
166	    baselinePath,
167	    "--test",
168	    currentPath,
169	    "--basename",
170	    diffBasePath
171	  ]);
172	  const metrics = parseFlipOutput(stdout);
173	  const pass = metrics.mean <= thresholds.mean && metrics.max <= thresholds.max;
174	
175	  return {
176	    case: id,
177	    metric: "flip",
178	    mean: roundMetric(metrics.mean),
179	    p95: undefined,
180	    max: roundMetric(metrics.max),
181	    thresholds,
