195	export function perceptualDistance(baselineData, currentData, offset) {
196	  const baseAlpha = baselineData[offset + 3] / 255;
197	  const currentAlpha = currentData[offset + 3] / 255;
198	  const alphaDelta = Math.abs(baseAlpha - currentAlpha);
199	  const dr = srgbToLinear(baselineData[offset] / 255) - srgbToLinear(currentData[offset] / 255);
200	  const dg = srgbToLinear(baselineData[offset + 1] / 255) - srgbToLinear(currentData[offset + 1] / 255);
201	  const db = srgbToLinear(baselineData[offset + 2] / 255) - srgbToLinear(currentData[offset + 2] / 255);
202	  const colorDistance = Math.sqrt(0.2126 * dr * dr + 0.7152 * dg * dg + 0.0722 * db * db);
203	
204	  return Math.min(1, Math.sqrt(colorDistance * colorDistance + alphaDelta * alphaDelta));
205	}
