207	function writeHeatmapPixel(data, offset, distance) {
208	  const clamped = Math.max(0, Math.min(1, distance));
209	  const intensity = Math.round(clamped * 255);
210	  const red = clamped < 0.5 ? Math.round(clamped * 2 * 255) : 255;
211	  const green = clamped < 0.5 ? 255 : Math.round((1 - (clamped - 0.5) * 2) * 255);
212	
213	  data[offset] = red;
214	  data[offset + 1] = green;
215	  data[offset + 2] = 0;
216	  data[offset + 3] = intensity;
217	}
