350	function runFlip(executable, args) {
351	  return new Promise((resolve, reject) => {
352	    const child = spawn(executable, args, {
353	      windowsHide: true,
354	      stdio: ["ignore", "pipe", "pipe"]
355	    });
356	    let stdout = "";
357	    let stderr = "";
358	
359	    child.stdout.setEncoding("utf8");
360	    child.stderr.setEncoding("utf8");
361	    child.stdout.on("data", chunk => {
362	      stdout += chunk;
363	    });
364	    child.stderr.on("data", chunk => {
365	      stderr += chunk;
366	    });
367	    child.on("error", error => {
368	      reject(new Error(`Failed to run NVIDIA FLIP executable "${executable}": ${error.message}`));
369	    });
370	    child.on("close", code => {
371	      if (code === 0) {
372	        resolve({ stdout, stderr });
373	        return;
374	      }
375	      reject(new Error(`NVIDIA FLIP exited with code ${code}\n${stderr || stdout}`));
376	    });
377	  });
378	}
