1	import type { MaterialRuntimeState } from "../../parser/model/modelTypes.js";
2	import * as THREE from "three";
3	
4	import { clampColor } from "../utils.js";
5	import { mmdMaterialDepthWrite, mmdMaterialSuppressesColorAtAlpha } from "./material-metadata.js";
6	
7	type ShaderUniformMap = Record<string, { value: unknown }>;
8	const mmdDirectionalLightPositionScratch = new THREE.Vector3();
9	const mmdDirectionalLightTargetScratch = new THREE.Vector3();
10	const mmdDirectionalLightNormalizedScratch = new THREE.Vector3();
11	
12	export function syncMmdMaterialStates(
13	  materials: THREE.Material | THREE.Material[],
14	  states: readonly MaterialRuntimeState[]
15	): void {
16	  const materialList = Array.isArray(materials) ? materials : [materials];
17	  materialList.forEach((material, index) => {
18	    const state = states[index];
19	    if (!state) {
20	      return;
21	    }
22	    const materialColor = (material as { color?: unknown }).color;
23	    if (materialColor instanceof THREE.Color) {
24	      materialColor.setRGB(
25	        clampColor(state.diffuse[0]),
26	        clampColor(state.diffuse[1]),
27	        clampColor(state.diffuse[2])
28	      );
29	    }
30	    material.opacity = clampColor(state.diffuse[3]);
31	    const flags = material.userData.mmdMaterial?.flags;
32	    const suppressColor = mmdMaterialSuppressesColorAtAlpha(material.opacity, flags);
33	    const transparencyMode = material.userData.mmdMaterial?.transparencyMode;
34	    const usesAlphaBlend = transparencyMode === "alphaBlend";
35	    material.visible = material.opacity > 0 || suppressColor;
36	    material.colorWrite = !suppressColor;
37	    material.transparent = usesAlphaBlend || material.opacity < 1;
38	    material.depthWrite = transparencyMode
39	      ? mmdMaterialDepthWrite(transparencyMode)
40	      : !material.transparent;
41	    material.userData.mmdMaterialState = {
42	      diffuse: [...state.diffuse],
43	      specular: [...state.specular],
44	      specularPower: state.specularPower,
45	      ambient: [...state.ambient],
46	      edgeColor: [...state.edgeColor],
47	      edgeSize: state.edgeSize,
48	      textureFactor: [...state.textureFactor],
49	      sphereTextureFactor: [...state.sphereTextureFactor],
50	      toonTextureFactor: [...state.toonTextureFactor]
51	    };
52	    const sphereShader = material.userData.mmdSphereShader as
53	      | { uniforms?: ShaderUniformMap }
54	      | undefined;
55	    const materialFactorShader = material.userData.mmdMaterialFactorShader as
56	      | { uniforms?: ShaderUniformMap }
57	      | undefined;
58	    const emissive = (material as { emissive?: unknown }).emissive;
59	    if (
60	      !material.userData.mmdMaterialFactors?.shaderApplied &&
61	      !materialFactorShader &&
62	      emissive instanceof THREE.Color
63	    ) {
64	      emissive.setRGB(
65	        clampColor(state.ambient[0]),
66	        clampColor(state.ambient[1]),
67	        clampColor(state.ambient[2])
68	      );
69	    }
70	    const diffuseColorUniform = materialFactorShader?.uniforms?.mmdDiffuseColor?.value;
71	    if (diffuseColorUniform instanceof THREE.Color) {
72	      diffuseColorUniform.setRGB(
73	        clampColor(state.diffuse[0]),
74	        clampColor(state.diffuse[1]),
75	        clampColor(state.diffuse[2])
76	      );
77	    }
78	    const textureFactor = materialFactorShader?.uniforms?.mmdTextureFactor?.value;
79	    if (textureFactor instanceof THREE.Vector4) {
80	      textureFactor.set(
81	        state.textureFactor[0],
82	        state.textureFactor[1],
83	        state.textureFactor[2],
84	        state.textureFactor[3]
85	      );
86	    }
87	    const sphereFactor = sphereShader?.uniforms?.mmdSphereFactor?.value;
88	    if (sphereFactor instanceof THREE.Vector4) {
89	      sphereFactor.set(
90	        state.sphereTextureFactor[0],
91	        state.sphereTextureFactor[1],
92	        state.sphereTextureFactor[2],
93	        state.sphereTextureFactor[3]
94	      );
95	    }
96	    const toonFactor = materialFactorShader?.uniforms?.mmdToonTextureFactor?.value;
97	    if (toonFactor instanceof THREE.Vector4) {
98	      toonFactor.set(
99	        state.toonTextureFactor[0],
100	        state.toonTextureFactor[1],
101	        state.toonTextureFactor[2],
102	        state.toonTextureFactor[3]
103	      );
104	    }
105	    const materialAmbient = materialFactorShader?.uniforms?.mmdMaterialAmbient?.value;
106	    if (materialAmbient instanceof THREE.Color) {
107	      materialAmbient.setRGB(
108	        clampColor(state.ambient[0]),
109	        clampColor(state.ambient[1]),
110	        clampColor(state.ambient[2])
111	      );
112	    }
113	    const specularColor = materialFactorShader?.uniforms?.mmdSpecularColor?.value;
114	    if (specularColor instanceof THREE.Color) {
115	      specularColor.setRGB(
116	        clampColor(state.specular[0]),
117	        clampColor(state.specular[1]),
118	        clampColor(state.specular[2])
119	      );
120	    }
121	    const specularPower = materialFactorShader?.uniforms?.mmdSpecularPower?.value;
122	    const specularPowerUniform = materialFactorShader?.uniforms?.mmdSpecularPower;
123	    if (typeof specularPower === "number" && specularPowerUniform) {
124	      specularPowerUniform.value = state.specularPower;
125	    }
126	    material.needsUpdate = true;
127	  });
128	}
